  <text x="20" y="48" fill="#71717a" font-size="12" font-family="sans-serif">Échantillon n=3, degrés de liberté=2 — trop petit pour un intervalle de confiance valable</text>
  <line x1="545" y1="65" x2="545" y2="270" stroke="#a1a1aa" stroke-width="1.5" stroke-dasharray="4,4"/>
  <text x="545" y="58" fill="#a1a1aa" font-size="12.5" font-weight="700" text-anchor="middle">Moyenne : 480 jours</text>
  <text x="20" y="76" fill="#d4d4d8" font-size="13" font-family="sans-serif">1er · 28/11/2012 → 30/11/2013</text>
  <rect x="150" y="82" width="301" height="28" fill="#8b5cf6" opacity="0.55" rx="4"/>
  <text x="461" y="101" fill="#fafafa" font-size="14" font-weight="700" font-family="sans-serif">367 jours</text>
  <text x="20" y="146" fill="#d4d4d8" font-size="13" font-family="sans-serif">2e · 9/7/2016 → 17/12/2017</text>
  <rect x="150" y="152" width="432" height="28" fill="#8b5cf6" opacity="0.72" rx="4"/>
